import{_ as t,o as n,c,a0 as i}from"./chunks/framework.jwovEGr5.js";const l=JSON.parse('{"title":"Hỗ trợ","description":"","frontmatter":{"title":"Hỗ trợ","sidebar_position":4},"headers":[],"relativePath":"support.md","filePath":"support.md"}'),a={name:"support.md"};function e(o,h,r,p,s,u){return n(),c("div",null,[...h[0]||(h[0]=[i('<h1 id="ho-tro" tabindex="-1">Hỗ trợ <a class="header-anchor" href="#ho-tro" aria-label="Permalink to &quot;Hỗ trợ&quot;">​</a></h1><p>Mô-đun Hỗ trợ trong ABNERP giúp doanh nghiệp quản lý các hoạt động hỗ trợ khách hàng và bảo trì sản phẩm sau bán hàng. Mô-đun này đảm bảo mọi yêu cầu hỗ trợ được theo dõi, xử lý kịp thời và có hệ thống, nâng cao sự hài lòng của khách hàng.</p><h2 id="lich-bao-tri-maintenance-schedule" tabindex="-1">Lịch bảo trì (Maintenance Schedule) <a class="header-anchor" href="#lich-bao-tri-maintenance-schedule" aria-label="Permalink to &quot;Lịch bảo trì (Maintenance Schedule)&quot;">​</a></h2><p>Lịch bảo trì cho phép thiết lập các kế hoạch bảo trì định kỳ cho sản phẩm hoặc thiết bị đã bàn giao cho khách hàng. Bạn có thể cấu hình tần suất bảo trì theo ngày, tuần, tháng hoặc năm, và hệ thống sẽ tự động tạo phiếu bảo trì khi đến hạn. Cảnh báo bảo trì sắp đến hạn được gửi đến bộ phận kỹ thuật và khách hàng qua email.</p><h2 id="phieu-bao-tri-maintenance-ticket" tabindex="-1">Phiếu bảo trì (Maintenance Ticket) <a class="header-anchor" href="#phieu-bao-tri-maintenance-ticket" aria-label="Permalink to &quot;Phiếu bảo trì (Maintenance Ticket)&quot;">​</a></h2><p>Phiếu bảo trì ghi nhận chi tiết công việc bảo trì thực tế: kỹ thuật viên phụ trách, thời gian thực hiện, công việc đã làm, linh kiện thay thế và chi phí phát sinh. Mỗi phiếu bảo trì liên kết với hợp đồng bảo trì hoặc thông tin bảo hành của sản phẩm, giúp kiểm soát chi phí bảo trì trong hạn mức cho phép. Lịch sử bảo trì được lưu trữ đầy đủ, phục vụ cho việc phân tích độ tin cậy của sản phẩm.</p><h2 id="quan-ly-su-co-issue-management" tabindex="-1">Quản lý sự cố (Issue Management) <a class="header-anchor" href="#quan-ly-su-co-issue-management" aria-label="Permalink to &quot;Quản lý sự cố (Issue Management)&quot;">​</a></h2><p>Khi khách hàng gặp sự cố với sản phẩm hoặc dịch vụ, bạn có thể tạo phiếu sự cố và phân công cho nhân viên hỗ trợ phù hợp. ABNERP hỗ trợ phân loại sự cố theo mức độ nghiêm trọng (thấp, trung bình, cao, khẩn cấp) và theo loại sự cố. Hệ thống theo dõi thời gian phản hồi và thời gian giải quyết, đảm bảo đáp ứng các cam kết về chất lượng dịch vụ (SLA). Quy trình xử lý sự cố bao gồm các bước: tiếp nhận, phân tích, xử lý, xác nhận và đóng phiếu. Báo cáo sự cố cung cấp cái nhìn tổng quan về hiệu suất hỗ trợ, các sự cố phổ biến và thời gian giải quyết trung bình.</p>',8)])])}const b=t(a,[["render",e]]);export{l as __pageData,b as default};
